public class WordWrap_wrap_1_Test {

    @Test
    @DisplayName("maxWidth(0) throws IllegalArgumentException for non-positive width")
    public void test_TC10() {
        // GIVEN a builder from simple text
        Builder b = WordWrap.from("any");
        // WHEN/THEN calling maxWidth with non-positive triggers precondition
        assertThrows(IllegalArgumentException.class, () -> {
            b.maxWidth(0);
        });
    }

    @Test
    @DisplayName("from(File,charset) throws IORuntimeException when file not found")
    public void test_TC11() {
        // GIVEN no file exists
        File f = new File("nonexistent.txt");
        // WHEN calling from(File,Charset) THEN IORuntimeException
        assertThrows(IORuntimeException.class, () -> {
            WordWrap.from(f, StandardCharsets.UTF_8);
        });
    }

    @Test
    @DisplayName("override stringWidth to constant high value forces immediate broken-word without hyphens when breakWords=false")
    public void test_TC12() {
        // GIVEN text "abcde", maxWidth=1, stringWidth always too large forcing broken-word path, breakWords=false avoids hyphens
        Builder b = WordWrap.from("abcde")
                           .maxWidth(1)
                           .stringWidth(s -> 100)
                           .breakWords(false);
        // WHEN wrap
        String result = b.wrap();
        // THEN first char then newline, and no hyphens in rest
        assertAll(
            () -> assertEquals(true, result.startsWith("a\n"), "should start with first char and newline"),
            () -> assertFalse(result.contains("-"), "no hyphens should be inserted")
        );
    }

    @Test
    @DisplayName("newLine(\"\\r\\n\") uses CRLF as delimiter in output")
    public void test_TC13() {
        // GIVEN text with explicit newline, custom newLine CRLF
        Builder b = WordWrap.from("A\nB")
                           .newLine("\r\n");
        // WHEN wrap with default maxWidth large
        String out = b.wrap();
        // THEN lines separated by CRLF exactly
        assertEquals("A\r\nB", out);
    }

    @Test
    @DisplayName("includeExtraWordChars(\"?\") makes punctuation '?' be treated as part of word")
    public void test_TC14() {
        // GIVEN text "?X?" and '?' included as extra word char, so punctuation isn't split
        Builder b = WordWrap.from("?X?")
                           .includeExtraWordChars("?");
        // WHEN wrap
        String result = b.wrap();
        // THEN entire string appears intact
        assertEquals("?X?", result);
    }

    @Test
    @DisplayName("writeBrokenWord prefix branch without hyphen for short word (length=2)")
    public void test_TC15() {
        // GIVEN short word "AB" and maxWidth=1 triggers broken-word else-path no hyphens
        Builder b = WordWrap.from("AB")
                           .maxWidth(1);
        // WHEN wrap
        String out = b.wrap();
        // THEN each letter on its own line without hyphens
        assertEquals("A\nB", out);
    }

    @Test
    @DisplayName("close(reader) throws IORuntimeException when reader.close() throws IOException")
    public void test_TC16() throws Exception {
        // GIVEN a Reader stub that returns -1 then throws on close
        Reader stub = new Reader() {
            private boolean readOnce = false;
            @Override
            public int read(char[] cbuf, int off, int len) throws IOException {
                if (!readOnce) {
                    readOnce = true;
                    return -1;
                }
                return -1;
            }
            @Override
            public void close() throws IOException {
                throw new IOException("close fail");
            }
        };
        BufferedReader br = new BufferedReader(stub);
        // Use reflection to access package-private from(Reader,boolean)
        Method fromMethod = WordWrap.class.getDeclaredMethod("from", Reader.class, boolean.class);
        fromMethod.setAccessible(true);
        Builder b = (Builder) fromMethod.invoke(null, br, true);
        StringWriter out = new StringWriter();
        // WHEN wrap(writer) --> finally block calls close and should wrap IOException in IORuntimeException
        assertThrows(IORuntimeException.class, () -> {
            b.wrap(out);
        });
    }
}
